    #[test]
    fn run_with_asset_detail_failure_logs_error_and_skips_that_asset() {
        let search = FakeSearch::new(vec![bucket(vec![
            asset_with("good", "/mnt/qnap/good.jpg", "cs-good", None),
            asset_with("bad", "/mnt/qnap/bad.jpg", "cs-bad", None),
        ])]);
        let caption = FakeCaption::new();
        caption
            .asset_detail_failures
            .lock()
            .unwrap()
            .insert("bad".into());
        let vision = FakeVision {
            reply: "新描述".into(),
        };
        let mut cfg = cfg();
        cfg.people
            .insert("测试人物乙".into(), vec!["女儿".into(), "孩子".into()]);

        let mut log = Vec::new();
        run_with(&cfg, &search, &caption, &vision, args(), &mut log).unwrap();

        let updates = caption.updates.lock().unwrap();
        assert_eq!(updates.len(), 1);
        assert_eq!(updates[0].0, "good");

        let log_s = String::from_utf8(log).unwrap();
        assert!(log_s.contains("FAIL"), "{log_s}");
        assert!(
            log_s.contains("failed to fetch full asset detail for bad"),
            "{log_s}"
        );
        assert!(log_s.contains("done: 1 captioned, 1 failed"), "{log_s}");
    }

